var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"이제 끝이에요.","JPN":"もう終わりです。","ENG":"It's over.","TWN":"到此為止吧。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"……과연, 기억에서 봐왔던 당신보다 훨씬 강력한 힘이군요.","JPN":"……なるほど、記憶の中で見てきたあなたよりずっと強い力ですね。","ENG":"...You are much stronger than what I saw in the memories.","TWN":"……比記憶中的你強大許多的。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"역시 <color=#ffd34c>운명을 바친 대가</color>로 받은 힘인가요?","JPN":"やはり<color=#ffd34c>運命を捧げた対価</color>でもらった力だからですか？","ENG":"Is this the power you received <color=#ffd34c>in return for your fate</color>?","TWN":"果然，這就是<color=#ffd34c>以獻出命運為代價</color>所獲得的力量嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"하지만 나가파샤를 손에 넣는다 하더라도 달라지는 것은 없습니다.","JPN":"ですが、ナーガパーシャを手に入れたところで何も変わりません。","ENG":"However, nothing changes even if you possess Nagapasha.","TWN":"但即使你得到那伽羂索，也不會有什麼改變。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"당신이 노리고 있는 게 뭔지 알고 있거든요.","JPN":"あなたが何を狙っているのかはわかっています。","ENG":"I already know what you are after.","TWN":"我知道你在打什麼主意。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"바로 당신이 들고 있는 제 고유 무장인 <color=#ffd34c>차원 닻</color>의 시동 아닙니까?","JPN":"あなたが持っている私の固有武装、<color=#ffd34c>次元錨</color>の始動なのではないですか？","ENG":"Isn't it the activation of my Unique Gear, the <color=#ffd34c>Dimension Anchor</color> that you have in your hands?","TWN":"你不就是想啟動我的專屬裝備，<color=#ffd34c>次元錨</color>嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"차원 닻은 나가파샤의 보조 없이는 시동할 수 없는 무기니 말입니다.","JPN":"次元錨はナーガパーシャの補助なしでは始動できない武器ですからね。","ENG":"The Dimension Anchor is a weapon that cannot be started without Nagapasha.","TWN":"那個東西無法在沒有那伽羂索輔助的情況下啟動。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"하지만 잘 알다시피 우리 전대의 무장에는 <color=#ffd34c>만트라 코드</color> 와 <color=#ffd34c>생체 인식 코드</color>가 필요합니다.","JPN":"ですがご存じのとおり、私たちの戦隊の武装には<color=#ffd34c>マントラコード</color>と<color=#ffd34c>生体認識コード</color>が必要です。","ENG":"But as you may know, our division's gear requires a <color=#ffd34c>mantra code</color> and a <color=#ffd34c>biometric authentication code</color>.","TWN":"但你也知道吧，解鎖我們戰隊的武裝同時需要用到<color=#ffd34c>曼陀羅代碼</color>和<color=#ffd34c>生物識別代碼</color>。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"이건 오히려 당신이 잘 알고 있는 부분이지 않나요?","JPN":"これはむしろあなたのほうがよく知っているのでは？","ENG":"I'm sure you know this all too well, no?","TWN":"這些你應該比我更加了解，不是嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"이런……! 고유 무장이……!","JPN":"あっ……！　固有武装が……！","ENG":"Dammit...! My Unique Gear is...!","TWN":"可惡……！我的專屬裝備……！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"받아라. 차원 닻이다.","JPN":"受け取れ。次元錨だ。","ENG":"Take it. It's the Dimension Anchor.","TWN":"接著，這是次元錨。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"네? 하, 하지만…….","JPN":"えっ？　で、でも……","ENG":"What? B-but...","TWN":"什麼？可，可是……"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"상황이 좋진 않다. 나도 이제 얼마 남지 않았다는 걸 느껴.","JPN":"まずい状況だ。俺に残された時間もあまりないだろう。","ENG":"This doesn't look good. I feel that my end is near.","TWN":"情況不妙，我時間不多了。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"……네 이름조차 떠오르지 않으니 말이다.","JPN":"……お前の名前さえ思い出せないからな。","ENG":"...I can't even recall your name.","TWN":"……我現在連你的名字都想不起來了。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"그러니 부탁하마. 이름 없는 바람.","JPN":"だから、頼む。名の無き風。","ENG":"So, I leave it up to you, nameless wind.","TWN":"所以交給你了，無名的風。"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"인도하는 태양을 위해. 그리고 삿된 것을 정화하다 전사한 전우들을 위해.","JPN":"導いてくれる太陽のために。そして、邪なものを浄化して戦死した戦友のために。","ENG":"For the guiding sun. And for all our comrades who fell purifying the evil.","TWN":"為了引導之陽，為了淨化邪惡而犧牲的戰友們，"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"바루나스트라를 정화해라.","JPN":"ヴァルナストラを浄化しろ。","ENG":"Purify Varunastra.","TWN":"淨化伐樓拿之艦吧！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"하지만…… 만트라 코드를 알더라도 생체 인식 코드가 맞지 않으면 아무런 쓸모도 없어요.","JPN":"でも……マントラコードを知っていたとしても生体認識コードが合わなければ意味がありません。","ENG":"But... even if I know the mantra code, it's useless if the biometric authentication code doesn't match.","TWN":"但是……即便知道曼陀羅代碼，如果生物識別代碼不匹配也沒用吧。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"그건 걱정 말거라. 방법은 때가 되면 알게 될 것이다.","JPN":"案ずるな。方法など、その時になればわかるはずだ。","ENG":"Don't worry about that. You will find a way when the time comes.","TWN":"不用擔心，船到橋頭自然直。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_NULL","text":{"KOREA":"태양은 나아가고자 하는 자에게 빛을 내려주는 법이니.","JPN":"太陽は前に進もうとする者に光を与えてくれるものだから。","ENG":"The sun gives light to those who wish to go forward.","TWN":"太陽總會照耀那些勇往直前的人。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};